import React, { useState, useEffect } from 'react';
import { Routes, Route, Link, useLocation, useNavigate } from 'react-router-dom';
import axios from 'axios';
import './App.css';
import BookList from './pages/BookList';
import MyBorrows from './pages/MyBorrows';
import Notifications from './pages/Notifications';
import AdminBooks from './pages/AdminBooks';
import Login from './pages/Login';

function App() {
  const [currentUser, setCurrentUser] = useState(null); // { role: 'admin'|'user', id, name }
  const [toast, setToast] = useState({ show: false, message: '', type: 'success' });

  const location = useLocation();
  const navigate = useNavigate();

  // Load user session from local storage on mount
  useEffect(() => {
    const savedUser = localStorage.getItem('lms_user');
    if (savedUser) {
      setCurrentUser(JSON.parse(savedUser));
    }
  }, []);

  const showToast = (message, type = 'success') => {
    setToast({ show: true, message, type });
    setTimeout(() => {
      setToast(prev => ({ ...prev, show: false }));
    }, 4000);
  };

  const handleLogin = (userSession) => {
    setCurrentUser(userSession);
    localStorage.setItem('lms_user', JSON.stringify(userSession));
    showToast(`Welcome back, ${userSession.name}!`, 'success');
    if (userSession.role === 'admin') {
      navigate('/admin');
    } else {
      navigate('/');
    }
  };

  const handleLogout = () => {
    showToast("Logged out successfully.", "info");
    setCurrentUser(null);
    localStorage.removeItem('lms_user');
    navigate('/');
  };

  if (!currentUser) {
    return (
      <div className="login-page-container">
        {toast.show && (
          <div className={`toast-notification toast-${toast.type}`}>
            {toast.message}
          </div>
        )}
        <Login onLogin={handleLogin} />
      </div>
    );
  }

  return (
    <div className="app-container">
      {/* Toast Notification Container */}
      {toast.show && (
        <div className={`toast-notification toast-${toast.type}`}>
          {toast.message}
        </div>
      )}

      <header className="app-header">
        <div className="brand-section">
          <span className="brand-logo">📚</span>
          <div>
            <h1>Library Management</h1>
            <p className="brand-subtitle">Smart Borrowing & Waitlist System</p>
          </div>
        </div>

        <div className="user-profile-widget">
          <div className="profile-details">
            <span className="profile-name">{currentUser.name}</span>
            <span className={`profile-role role-${currentUser.role}`}>{currentUser.role.toUpperCase()}</span>
          </div>
          <button className="btn btn-logout btn-sm" onClick={handleLogout}>
            Logout
          </button>
        </div>
      </header>

      <nav className="main-nav">
        <div className="nav-links">
          {currentUser.role === 'user' && (
            <>
              <Link to="/" className={`nav-link ${location.pathname === '/' ? 'active' : ''}`}>
                📖 Book Catalog
              </Link>
              <Link to="/borrows" className={`nav-link ${location.pathname === '/borrows' ? 'active' : ''}`}>
                📋 My Borrows
              </Link>
              <Link to="/notifications" className={`nav-link ${location.pathname === '/notifications' ? 'active' : ''}`}>
                🔔 Notifications
              </Link>
            </>
          )}
          {currentUser.role === 'admin' && (
            <Link to="/admin" className={`nav-link ${location.pathname === '/admin' ? 'active' : ''}`}>
              ⚙️ Admin Dashboard
            </Link>
          )}
        </div>
      </nav>

      <main className="content-area">
        <Routes>
          {currentUser.role === 'user' ? (
            <>
              <Route path="/" element={<BookList currentUserId={currentUser.id} showToast={showToast} />} />
              <Route path="/borrows" element={<MyBorrows currentUserId={currentUser.id} showToast={showToast} />} />
              <Route path="/notifications" element={<Notifications currentUserId={currentUser.id} showToast={showToast} />} />
              <Route path="*" element={<BookList currentUserId={currentUser.id} showToast={showToast} />} />
            </>
          ) : (
            <>
              <Route path="/admin" element={<AdminBooks showToast={showToast} />} />
              <Route path="*" element={<AdminBooks showToast={showToast} />} />
            </>
          )}
        </Routes>
      </main>
    </div>
  );
}

export default App;
